const rawContent = $input.all()[0].json.message.content;
  const combinedData = $('Step 5: Combine Content4').first().json;

  const funder = combinedData.funder_name;
  const deadline = combinedData.deadline;
  const grantId = combinedData.grantId;
  const org_id = combinedData.org_id;

  // Parse AI response
  let proposal;
  try {
    let cleaned = rawContent.trim();
    cleaned = cleaned.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
    proposal = JSON.parse(cleaned).grant_proposal;
  } catch (e) {
    throw new Error("Failed to parse AI response JSON: " + e.message);
  }

  const orgName = proposal.organization || 'Organization';
  const grantTitle = combinedData.grant_title || proposal.project_title || 'Grant Proposal';

  // Helper to extract markdown tables
  function extractTable(text) {
    const lines = text.split('\n');
    const tableLines = [];
    const remainingLines = [];

    lines.forEach(line => {
      if (line.includes('|')) tableLines.push(line);
      else remainingLines.push(line);
    });

    return {
      content: remainingLines.join('\n').trim() || null,
      tabulation: tableLines.length ? tableLines.join('\n') : null
    };
  }

  // Helper to detect if a line is a header
  function isHeader2(line) {
    if (/^\*\*.+:\*\*$/.test(line)) return true;
    if (line.length < 60 && /:$/.test(line)) return true;
    return false;
  }

  const sections = [];
  let sectionIndex = 1;

  // =============================
  // 1️⃣ TOP TITLE META SECTION
  // =============================
  sections.push({
    title: orgName + ' Proposal' ,
    header1: null,
    header2: null,
    content: [
    ...(funder ? [{ chapter: 'Funder: ' + funder, sort_order: 1 }] : []),
    { chapter: 'Deadline: ' + (deadline || 'Not specified'), sort_order: 2 },
    { chapter: 'Grant: ' + grantTitle, sort_order: 3 },
  ],
    tabulation: null,
    sort_order: sectionIndex++,
  });

  // =============================
  // 2️⃣ BUILD ACTUAL PROPOSAL SECTIONS FIRST
  // =============================
  const proposalSections = [];
  const tocChapters = [];

  let tocIndex = 1;

  for (const [sectionKey, sectionContent] of Object.entries(proposal.sections)) {
    // Skip duplicate sections
    if (/_duplicate/.test(sectionKey)) continue;

    let sortOrder = 1;
    const header1Arr = [];
    const header2Arr = [];
    const contentArr = [];
    const tabulationArr = [];

    const sectionTitle = sectionKey
      .replace(/^\d+_/, '')
      .replace(/_/g, ' ')
      .replace(/\b\w/g, l => l.toUpperCase());

    tocChapters.push({
      chapter: `${tocIndex}. ${sectionTitle}`,
      sort_order: tocIndex
    });

    tocIndex++;

    const { content: mainContent, tabulation } = extractTable(sectionContent);

    if (mainContent) {
      mainContent.split('\n').forEach(line => {
        const trimmed = line.trim();
        if (!trimmed) return;

        if (isHeader2(trimmed)) {
          header2Arr.push({ chapter: trimmed, sort_order: sortOrder++ });
        } else {
          contentArr.push({ chapter: trimmed, sort_order: sortOrder++ });
        }
      });
    }

    if (tabulation) {
      tabulationArr.push({ chapter: tabulation, sort_order: sortOrder++ });
    }

    proposalSections.push({
      title: sectionTitle,
      header1: header1Arr.length ? header1Arr : null,
      header2: header2Arr.length ? header2Arr : null,
      content: contentArr.length ? contentArr : null,
      tabulation: tabulationArr.length ? tabulationArr : null,
    });
  }

  // =============================
  // 3️⃣ INSERT TABLE OF CONTENTS
  // =============================
  sections.push({
    title: 'Table of Contents',
    header1: null,
    header2: null,
    content: tocChapters,
    tabulation: null,
    sort_order: sectionIndex++,
  });

  // =============================
  // 4️⃣ APPEND REAL SECTIONS
  // =============================
  proposalSections.forEach(sec => {
    sections.push({
      ...sec,
      sort_order: sectionIndex++,
    });
  });

  // =============================
  // FINAL RETURN
  // =============================
  return [{
    json: {
      proposalData: {
        org_id: org_id,
        grant_id: grantId,
        title: orgName,
        status: 'draft',
        sections: sections,
      },
      proposalMarkdown: rawContent,
      funder: funder,
      deadline: deadline,
      focus: combinedData.grant_description || '',
      alignmentScore: null,
      complianceScore: null,
      warnings: [],
    }
  }];

